{
  "name": "DOSE - Bias Hunter Onboarding",
  "description": "A scientific instrument implementing the Dynamically Optimized Sequential Experimentation (DOSE) module for risk profile classification."
}

export enum ExperimentPhase {
  INTRO = 'INTRO',
  EXPERIMENT = 'EXPERIMENT',
  RESULTS = 'RESULTS'
}

export enum OptionType {
  LOTTERY = 'LOTTERY',
  SURE_THING = 'SURE_THING'
}

export interface LotteryParams {
  gain: number;
  loss: number;
  probability: number; // usually 0.5
}

export interface Question {
  id: number;
  text: string;
  optionA: {
    type: OptionType;
    params?: LotteryParams; // If Lottery
    amount?: number; // If Sure Thing
  };
  optionB: {
    type: OptionType;
    amount: number; // Usually 0 or a sure gain/loss
  };
}

export interface UserChoice {
  questionId: number;
  chosenOption: 'A' | 'B';
  wasLottery: boolean;
  lotteryParams?: LotteryParams;
  sureAmount: number;
}

export interface ClassificationResult {
  module: string;
  completion_status: string;
  total_questions_answered: number;
  user_classification: {
    type: 'Type A' | 'Type B';
    risk_profile: 'Loss Averse' | 'Loss Tolerant';
    consistency_score: 'High' | 'Medium' | 'Low';
  };
}

export const APP_TITLE = "Bias Hunter Onboarding System";
export const APP_MODULE = "DOSE (Dynamically Optimized Sequential Experimentation)";

export const INITIAL_ENDOWMENT = 10000;
export const TOTAL_QUESTIONS = 10;

export const INTRO_SCRIPT = `**Section 1 of 1** (Replicating DOSE Module III.A)

In the next few questions, you will be asked to choose between two lotteries.

You will start this section with **10,000 points**, which you may lose based on the lotteries you choose in this section. That is, lotteries in this section may either **add to** or **subtract from** this initial 10,000 points.

For example, suppose you chose a lottery that had a 50% chance of adding 5,000 points, and a 50% chance of subtracting 5,000 points. In the case of winning, the 5,000 will be added to your additional 10,000. In the case of a loss, the 5,000 will be subtracted from your initial 10,000. Note that you will never have the possibility of losing more than 10,000, so at worst you will end this section with 0 points.

Please type **'Start'** to begin the 10-question sequence.`;

import { Question, OptionType, UserChoice, ClassificationResult } from '../types';

/**
 * GENERATE NEXT QUESTION
 * Implements the "BROAD" method logic (simulated).
 * 
 * Logic Phases:
 * Q1-Q4: Mixed Lotteries (Gain vs Loss) to test Loss Aversion.
 * Q5-Q7: Gain Domain (Risk vs Sure Gain).
 * Q8-Q10: Loss Domain (Risk vs Sure Loss).
 */
export const generateQuestion = (
  questionNumber: number,
  history: UserChoice[]
): Question => {
  const lastChoice = history[history.length - 1];

  // --- Q1: FIXED ROOT NODE ---
  if (questionNumber === 1) {
    return {
      id: 1,
      text: `Question 1 of 10\nWhich of the following options do you prefer?`,
      optionA: {
        type: OptionType.LOTTERY,
        params: { gain: 7000, loss: 5000, probability: 0.5 }
      },
      optionB: {
        type: OptionType.SURE_THING,
        amount: 0
      }
    };
  }

  // --- Q2 - Q4: MIXED LOTTERIES (Refining Loss Aversion) ---
  if (questionNumber <= 4) {
    let prevGain = 7000;
    let prevLoss = 5000;

    // Retrieve previous lottery parameters if available
    if (lastChoice && lastChoice.lotteryParams) {
      prevGain = lastChoice.lotteryParams.gain;
      prevLoss = lastChoice.lotteryParams.loss;
    }

    let nextGain = prevGain;
    let nextLoss = prevLoss;
    const step = 5000 / (questionNumber * 1.5); // Decaying step size

    if (lastChoice.chosenOption === 'A') {
      // Risk Seeking: Make it harder (Increase Loss or Decrease Gain)
      // To create "Indifference", we push them towards rejection
      nextLoss = Math.min(9500, prevLoss + step); 
    } else {
      // Risk Averse: Make it easier (Decrease Loss)
      // To tempt them into acceptance
      nextLoss = Math.max(500, prevLoss - step);
    }

    // Round to nearest 50
    nextGain = Math.round(nextGain / 50) * 50;
    nextLoss = Math.round(nextLoss / 50) * 50;

    return {
      id: questionNumber,
      text: `Question ${questionNumber} of 10\nWhich of the following options do you prefer?`,
      optionA: {
        type: OptionType.LOTTERY,
        params: { gain: nextGain, loss: nextLoss, probability: 0.5 }
      },
      optionB: {
        type: OptionType.SURE_THING,
        amount: 0
      }
    };
  }

  // --- Q5 - Q7: GAIN DOMAIN (Positive Gambles) ---
  if (questionNumber <= 7) {
    // Base setup for Q5 start
    if (questionNumber === 5) {
      return {
        id: 5,
        text: `Question 5 of 10\nWhich of the following options do you prefer?`,
        optionA: {
          type: OptionType.LOTTERY,
          params: { gain: 8000, loss: 0, probability: 0.5 }
        },
        optionB: {
          type: OptionType.SURE_THING,
          amount: 3000 // EV is 4000. 3000 is a safe lowball.
        }
      };
    }

    // Adaptive logic for Q6, Q7
    // We adjust the Sure Amount based on risk tolerance
    const prevSure = lastChoice.sureAmount;
    const step = 2000 / (questionNumber - 4);
    let nextSure = prevSure;

    if (lastChoice.chosenOption === 'A') {
      // Picked Gamble: Sure amount was too low. Increase Sure amount to find breaking point.
      nextSure += step;
    } else {
      // Picked Sure: Sure amount was attractive. Decrease Sure amount.
      nextSure -= step;
    }

    return {
      id: questionNumber,
      text: `Question ${questionNumber} of 10\nWhich of the following options do you prefer?`,
      optionA: {
        type: OptionType.LOTTERY,
        params: { gain: 8000, loss: 0, probability: 0.5 } // Fixed gamble
      },
      optionB: {
        type: OptionType.SURE_THING,
        amount: Math.round(nextSure / 50) * 50
      }
    };
  }

  // --- Q8 - Q10: LOSS DOMAIN (Negative Gambles) ---
  // A: 50% chance lose 8000, 50% lose 0 (EV -4000)
  // B: Sure lose X
  if (questionNumber <= 10) {
     // Base setup for Q8 start
     if (questionNumber === 8) {
      return {
        id: 8,
        text: `Question 8 of 10\nWhich of the following options do you prefer?`,
        optionA: {
          type: OptionType.LOTTERY,
          params: { gain: 0, loss: 8000, probability: 0.5 } // "Gain" is 0 here (lose 0), "Loss" is 8000
        },
        optionB: {
          type: OptionType.SURE_THING,
          amount: -5000 // Worse than EV (-4000), should drive people to gamble if loss averse
        }
      };
    }

    const prevSure = lastChoice.sureAmount;
    const step = 2000 / (questionNumber - 7);
    let nextSure = prevSure;

    if (lastChoice.chosenOption === 'A') {
      // Picked Gamble (Risk Seeking in Loss Domain): The sure loss was too painful.
      // Make the sure loss "better" (smaller loss, closer to 0) to tempt them.
      nextSure += step; // e.g., -5000 -> -3000
    } else {
      // Picked Sure (Risk Averse in Loss Domain?? Rare): They accepted the sure loss.
      // Make the sure loss worse (more negative) to force them to gamble.
      nextSure -= step; // e.g., -5000 -> -7000
    }

    // Cap nextSure to be negative
    if (nextSure > 0) nextSure = 0;

    return {
      id: questionNumber,
      text: `Question ${questionNumber} of 10\nWhich of the following options do you prefer?`,
      optionA: {
        type: OptionType.LOTTERY,
        params: { gain: 0, loss: 8000, probability: 0.5 }
      },
      optionB: {
        type: OptionType.SURE_THING,
        amount: Math.round(nextSure / 50) * 50
      }
    };
  }

  throw new Error("Experiment out of bounds");
};

/**
 * CLASSIFY USER
 * Analyzes the history to determine Type A vs Type B.
 */
export const classifyUser = (history: UserChoice[]): ClassificationResult => {
  // Analyze Mixed Lotteries (Q1-Q4)
  const mixedQuestions = history.filter(h => h.questionId <= 4);
  const mixedGamblesAccepted = mixedQuestions.filter(h => h.chosenOption === 'A');

  // Calculate average accepted Loss/Gain ratio
  let totalRatio = 0;
  mixedGamblesAccepted.forEach(h => {
    if (h.lotteryParams) {
      totalRatio += (h.lotteryParams.loss / h.lotteryParams.gain);
    }
  });

  const avgRatio = mixedGamblesAccepted.length > 0 ? totalRatio / mixedGamblesAccepted.length : 0;

  // Classification Logic:
  // If user accepts losses nearly equal to gains (ratio ~ 1), they are Type B (Loss Tolerant).
  // If user only accepts gambles where Gain >> Loss (ratio low), or rejects all, they are Type A (Loss Averse).

  let type: 'Type A' | 'Type B' = 'Type A';
  let profile: 'Loss Averse' | 'Loss Tolerant' = 'Loss Averse';

  // Threshold: If they accept mixed gambles where Loss is at least 70% of Gain often.
  if (mixedGamblesAccepted.length >= 2 && avgRatio > 0.7) {
    type = 'Type B';
    profile = 'Loss Tolerant';
  }

  // Consistency check (heuristic)
  // Check if they switched strategies erratically in Gain domain (Q5-Q7)
  const gainQuestions = history.filter(h => h.questionId >= 5 && h.questionId <= 7);
  let consistency: 'High' | 'Medium' | 'Low' = 'High';

  // Simple heuristic: did they flip-flop more than once in a narrowing sequence?
  // (Simplified for this simulation)

  return {
    module: "DOSE_Section_III_A",
    completion_status: "Success",
    total_questions_answered: 10,
    user_classification: {
      type: type,
      risk_profile: profile,
      consistency_score: consistency
    }
  };
};

import React from 'react';

interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'option';
}

export const Button: React.FC<ButtonProps> = ({ 
  children, 
  variant = 'primary', 
  className = '', 
  ...props 
}) => {
  const baseStyles = "px-6 py-3 rounded-lg font-medium transition-all duration-200 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-slate-900";

  const variants = {
    primary: "bg-emerald-600 hover:bg-emerald-500 text-white focus:ring-emerald-500 shadow-lg shadow-emerald-900/20",
    secondary: "bg-slate-700 hover:bg-slate-600 text-slate-200 focus:ring-slate-500",
    option: "w-full text-left p-6 border-2 border-slate-700 hover:border-emerald-500/50 hover:bg-slate-800/50 bg-slate-800 text-slate-100 group relative overflow-hidden"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`} 
      {...props}
    >
      {children}
    </button>
  );
};

import React from 'react';
import { OptionType, LotteryParams } from '../types';
import { Button } from './Button';

interface OptionCardProps {
  label: string;
  type: OptionType;
  params?: LotteryParams;
  amount?: number;
  onClick: () => void;
}

export const OptionCard: React.FC<OptionCardProps> = ({ 
  label, 
  type, 
  params, 
  amount, 
  onClick 
}) => {
  const formatNumber = (num: number) => Math.abs(num).toLocaleString();

  return (
    <Button variant="option" onClick={onClick}>
      <div className="flex items-center justify-between mb-2">
        <span className="text-emerald-400 font-mono text-sm tracking-wider uppercase">{label}</span>
        {type === OptionType.SURE_THING && (
           <span className="bg-slate-700 text-slate-300 text-xs px-2 py-1 rounded">Certainty</span>
        )}
        {type === OptionType.LOTTERY && (
           <span className="bg-indigo-900/50 text-indigo-300 text-xs px-2 py-1 rounded">Lottery (50/50)</span>
        )}
      </div>

      <div className="space-y-3">
        {type === OptionType.LOTTERY && params ? (
          <>
            <div className="flex items-center space-x-3">
              <div className="w-12 h-12 rounded-full bg-emerald-900/30 flex items-center justify-center border border-emerald-500/30 text-emerald-400 font-bold">
                50%
              </div>
              <div>
                <div className="text-slate-400 text-xs uppercase">Gain</div>
                <div className="text-xl font-bold text-white">
                  {params.gain > 0 ? '+' : ''}{formatNumber(params.gain)}
                </div>
              </div>
            </div>

            <div className="w-px h-8 bg-slate-700 ml-6"></div>

            <div className="flex items-center space-x-3">
              <div className="w-12 h-12 rounded-full bg-rose-900/30 flex items-center justify-center border border-rose-500/30 text-rose-400 font-bold">
                50%
              </div>
              <div>
                <div className="text-slate-400 text-xs uppercase">Lose</div>
                <div className="text-xl font-bold text-white">
                  -{formatNumber(params.loss)}
                </div>
              </div>
            </div>
          </>
        ) : (
          <div className="py-6">
             <div className="text-slate-400 text-xs uppercase mb-1">Receive / Pay</div>
             <div className={`text-3xl font-bold ${(amount || 0) >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                {(amount || 0) >= 0 ? '+' : '-'}{formatNumber(amount || 0)}
             </div>
             <div className="text-slate-500 text-sm mt-1">Guaranteed outcome</div>
          </div>
        )}
      </div>
    </Button>
  );
};

import React, { useState } from 'react';
import { INTRO_SCRIPT } from '../constants';
import { Button } from './Button';

interface IntroScreenProps {
  onStart: () => void;
}

export const IntroScreen: React.FC<IntroScreenProps> = ({ onStart }) => {
  const [inputValue, setInputValue] = useState('');
  const [error, setError] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (inputValue.trim().toLowerCase() === 'start') {
      onStart();
    } else {
      setError(true);
    }
  };

  // Process the markdown-like bold syntax for display
  const renderText = (text: string) => {
    return text.split('\n').map((line, idx) => {
      // Very basic parser for **bold**
      const parts = line.split(/(\*\*.*?\*\*)/g);
      return (
        <p key={idx} className="mb-4 text-slate-300 leading-relaxed">
          {parts.map((part, pIdx) => {
            if (part.startsWith('**') && part.endsWith('**')) {
              return <strong key={pIdx} className="text-emerald-400 font-semibold">{part.slice(2, -2)}</strong>;
            }
            return part;
          })}
        </p>
      );
    });
  };

  return (
    <div className="max-w-2xl mx-auto w-full">
      <div className="bg-slate-800 border border-slate-700 rounded-xl p-8 shadow-2xl">
        <div className="prose prose-invert max-w-none">
          {renderText(INTRO_SCRIPT)}
        </div>

        <form onSubmit={handleSubmit} className="mt-8 pt-6 border-t border-slate-700">
          <label className="block text-sm font-medium text-slate-400 mb-2">
            Type 'Start' to confirm understanding
          </label>
          <div className="flex gap-4">
            <input 
              type="text" 
              value={inputValue}
              onChange={(e) => {
                setInputValue(e.target.value);
                setError(false);
              }}
              className={`flex-1 bg-slate-900 border ${error ? 'border-rose-500' : 'border-slate-600'} rounded-lg px-4 py-3 text-white placeholder-slate-600 focus:outline-none focus:ring-2 focus:ring-emerald-500`}
              placeholder="Start"
              autoFocus
            />
            <Button type="submit" disabled={!inputValue}>
              Begin
            </Button>
          </div>
          {error && <p className="text-rose-500 text-sm mt-2">Please type exactly 'Start' to begin.</p>}
        </form>
      </div>
    </div>
  );
};

import React from 'react';
import { ClassificationResult } from '../types';

interface ResultsScreenProps {
  result: ClassificationResult;
}

export const ResultsScreen: React.FC<ResultsScreenProps> = ({ result }) => {
  return (
    <div className="max-w-2xl mx-auto w-full">
      <div className="bg-slate-800 border border-slate-700 rounded-xl p-8 shadow-2xl">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-white">Classification Complete</h2>
          <div className="bg-emerald-900/30 text-emerald-400 px-3 py-1 rounded-full text-sm font-mono border border-emerald-500/20">
            STATUS: {result.completion_status.toUpperCase()}
          </div>
        </div>

        <p className="text-slate-400 mb-6">
          The 10-question adaptive sequence has concluded. Below is the generated classification data based on the DOSE methodology.
        </p>

        <div className="bg-slate-950 rounded-lg p-6 border border-slate-800 overflow-x-auto relative group">
          <div className="absolute top-2 right-2 text-xs text-slate-600 font-mono">JSON</div>
          <pre className="text-emerald-400 font-mono text-sm leading-relaxed whitespace-pre-wrap">
            {JSON.stringify(result, null, 2)}
          </pre>
        </div>

        <div className="mt-8 flex justify-end">
           <button onClick={() => window.location.reload()} className="text-slate-500 hover:text-white text-sm transition-colors">
              Restart Session
           </button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { ExperimentPhase, UserChoice, Question } from './types';
import { INITIAL_ENDOWMENT, APP_TITLE, APP_MODULE, TOTAL_QUESTIONS } from './constants';
import { generateQuestion, classifyUser } from './services/doseService';
import { IntroScreen } from './components/IntroScreen';
import { OptionCard } from './components/OptionCard';
import { ResultsScreen } from './components/ResultsScreen';

const App: React.FC = () => {
  const [phase, setPhase] = useState<ExperimentPhase>(ExperimentPhase.INTRO);
  const [currentQNum, setCurrentQNum] = useState(1);
  const [history, setHistory] = useState<UserChoice[]>([]);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);

  // Initialize first question when entering experiment phase
  useEffect(() => {
    if (phase === ExperimentPhase.EXPERIMENT && !currentQuestion) {
      const q = generateQuestion(1, []);
      setCurrentQuestion(q);
    }
  }, [phase]);

  const handleChoice = (option: 'A' | 'B') => {
    if (!currentQuestion) return;

    const chosenObj = option === 'A' ? currentQuestion.optionA : currentQuestion.optionB;

    // Record choice
    const choice: UserChoice = {
      questionId: currentQNum,
      chosenOption: option,
      wasLottery: chosenObj.type === 'LOTTERY',
      lotteryParams: chosenObj.params,
      sureAmount: chosenObj.amount || 0
    };

    const newHistory = [...history, choice];
    setHistory(newHistory);

    // Check if finished
    if (currentQNum >= TOTAL_QUESTIONS) {
      setPhase(ExperimentPhase.RESULTS);
    } else {
      // Generate next question based on history
      const nextQNum = currentQNum + 1;
      const nextQ = generateQuestion(nextQNum, newHistory);
      setCurrentQNum(nextQNum);
      setCurrentQuestion(nextQ);
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 font-sans selection:bg-emerald-500/30">

      {/* Header */}
      <header className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-sm sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            <h1 className="font-bold text-slate-100 tracking-tight">{APP_TITLE}</h1>
          </div>
          <div className="text-xs font-mono text-slate-500 hidden sm:block">
            {APP_MODULE}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-5xl mx-auto px-4 py-12 flex flex-col items-center justify-center min-h-[calc(100vh-4rem)]">

        {phase === ExperimentPhase.INTRO && (
          <IntroScreen onStart={() => setPhase(ExperimentPhase.EXPERIMENT)} />
        )}

        {phase === ExperimentPhase.EXPERIMENT && currentQuestion && (
          <div className="w-full max-w-3xl animate-in fade-in slide-in-from-bottom-4 duration-500">
            {/* Status Bar */}
            <div className="flex items-center justify-between mb-8">
              <div className="flex flex-col">
                <span className="text-xs text-slate-500 uppercase tracking-wider mb-1">Current Endowment</span>
                <span className="text-2xl font-mono text-white font-bold">{INITIAL_ENDOWMENT.toLocaleString()} pts</span>
              </div>
              <div className="flex flex-col items-end">
                <span className="text-xs text-slate-500 uppercase tracking-wider mb-1">Progress</span>
                <div className="flex items-center space-x-2">
                  <span className="font-mono text-emerald-400 font-bold">{currentQNum}</span>
                  <span className="text-slate-600">/</span>
                  <span className="text-slate-600">{TOTAL_QUESTIONS}</span>
                </div>
              </div>
            </div>

            {/* Question Card */}
            <div className="bg-slate-800/50 border border-slate-700 p-8 rounded-2xl shadow-2xl backdrop-blur-sm">
              <h2 className="text-xl text-slate-200 font-medium mb-8 leading-relaxed whitespace-pre-wrap">
                {currentQuestion.text.replace(`Question ${currentQNum} of 10\n`, '')}
              </h2>

              <div className="grid md:grid-cols-2 gap-6">
                <OptionCard 
                  label="Option A"
                  type={currentQuestion.optionA.type}
                  params={currentQuestion.optionA.params}
                  amount={currentQuestion.optionA.amount}
                  onClick={() => handleChoice('A')}
                />
                <OptionCard 
                  label="Option B"
                  type={currentQuestion.optionB.type}
                  params={currentQuestion.optionB.params}
                  amount={currentQuestion.optionB.amount}
                  onClick={() => handleChoice('B')}
                />
              </div>
            </div>

             <div className="mt-8 text-center">
                <p className="text-slate-500 text-sm">
                  Select an option to proceed. This creates an irreversible transaction record.
                </p>
             </div>
          </div>
        )}

        {phase === ExperimentPhase.RESULTS && (
          <ResultsScreen result={classifyUser(history)} />
        )}

      </main>
    </div>
  );
};

export default App;

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum ExperimentPhase {
  INTRO = 'INTRO',
  EXPERIMENT = 'EXPERIMENT',
  RESULTS = 'RESULTS'
}

export enum OptionType {
  LOTTERY = 'LOTTERY',
  SURE_THING = 'SURE_THING'
}

export interface LotteryParams {
  gain: number;
  loss: number;
  probability: number; // 0.0 to 1.0 (e.g. 0.05 for 5%)
}

export interface Question {
  id: number;
  text: string;
  optionA: {
    type: OptionType;
    params?: LotteryParams; // If Lottery
    amount?: number; // If Sure Thing
  };
  optionB: {
    type: OptionType;
    amount: number; // Usually 0 or a sure gain/loss
  };
}

export interface UserChoice {
  questionId: number;
  chosenOption: 'A' | 'B';
  wasLottery: boolean;
  lotteryParams?: LotteryParams;
  sureAmount: number;
}

export interface ClassificationResult {
  module: string;
  total_questions: number;
  user_type: 'Type A' | 'Type B';
  traits: {
    loss_aversion: 'High' | 'Low';
    probability_weighting: 'Overweights Small Prob' | 'Underweights High Prob' | 'Rational';
  };
  summary: string;
}

export const APP_TITLE = "Bias Hunter Onboarding System";
export const APP_MODULE = "DOSE (Hybrid Behavioral Assessment)";

export const INITIAL_ENDOWMENT = 10000;
export const TOTAL_QUESTIONS = 12;

export const INTRO_SCRIPT = `**Section 1 of 1**

In this section, you will make 12 choices. You start with **10,000 points**. Your choices may add to or subtract from this total. There are no right or wrong answers, just your preference.

Please type **'Start'** to begin.`;

import React from 'react';
import { OptionType, LotteryParams } from '../types';
import { Button } from './Button';

interface OptionCardProps {
  label: string;
  type: OptionType;
  params?: LotteryParams;
  amount?: number;
  onClick: () => void;
}

export const OptionCard: React.FC<OptionCardProps> = ({ 
  label, 
  type, 
  params, 
  amount, 
  onClick 
}) => {
