interface OptionCardProps {
  label: string;
  type: OptionType;
  params?: LotteryParams;
  amount?: number;
  onClick: () => void;
}

export const OptionCard: React.FC<OptionCardProps> = ({ 
  label, 
  type, 
  params, 
  amount, 
  onClick 
}) => {
  const formatNumber = (num: number) => Math.abs(num).toLocaleString();

  const getProbColor = (prob: number) => {
    if (prob <= 0.1) return "bg-purple-900/30 border-purple-500/30 text-purple-400";
    if (prob >= 0.9) return "bg-emerald-900/30 border-emerald-500/30 text-emerald-400";
    return "bg-indigo-900/30 border-indigo-500/30 text-indigo-400";
  };

  return (
    <Button variant="option" onClick={onClick}>
      <div className="flex items-center justify-between mb-2">
        <span className="text-emerald-400 font-mono text-sm tracking-wider uppercase">{label}</span>
        {type === OptionType.SURE_THING && (
           <span className="bg-slate-700 text-slate-300 text-xs px-2 py-1 rounded">確定</span>
        )}
        {type === OptionType.LOTTERY && params && (
           <span className="bg-indigo-900/50 text-indigo-300 text-xs px-2 py-1 rounded">
             機率 ({Math.round(params.probability * 100)}/{Math.round((1 - params.probability) * 100)})
           </span>
        )}
      </div>

      <div className="space-y-3">
        {type === OptionType.LOTTERY && params ? (
          <>
            {/* Outcome 1 (Gain/Win) */}
            <div className="flex items-center space-x-3">
              <div className={`w-12 h-12 rounded-full flex items-center justify-center border font-bold text-sm ${getProbColor(params.probability)}`}>
                {Math.round(params.probability * 100)}%
              </div>
              <div>
                <div className="text-slate-400 text-xs uppercase">結果 1</div>
                <div className="text-xl font-bold text-white">
                  {params.gain > 0 ? '+' : ''}{formatNumber(params.gain)}
                </div>
              </div>
            </div>

            <div className="w-px h-8 bg-slate-700 ml-6"></div>

            {/* Outcome 2 (Loss/Nothing) */}
            <div className="flex items-center space-x-3">
              <div className={`w-12 h-12 rounded-full flex items-center justify-center border font-bold text-sm ${getProbColor(1 - params.probability)}`}>
                {Math.round((1 - params.probability) * 100)}%
              </div>
              <div>
                <div className="text-slate-400 text-xs uppercase">結果 2</div>
                <div className={`text-xl font-bold ${params.loss > 0 ? 'text-rose-400' : 'text-slate-300'}`}>
                  {params.loss > 0 ? `-${formatNumber(params.loss)}` : '0'}
                </div>
              </div>
            </div>
          </>
        ) : (
          <div className="py-6">
             <div className="text-slate-400 text-xs uppercase mb-1">獲得 / 支付</div>
             <div className={`text-3xl font-bold ${(amount || 0) >= 0 ? 'text-emerald-400' : 'text-rose-400'}`}>
                {(amount || 0) >= 0 ? '+' : '-'}{formatNumber(amount || 0)}
             </div>
             <div className="text-slate-500 text-sm mt-1">保證結果</div>
          </div>
        )}
      </div>
    </Button>
  );
};

