          if (chunk.web?.uri && chunk.web?.title) {
            sources.push({ uri: chunk.web.uri, title: chunk.web.title });
          }
        });
      }

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: responseText,
        groundingSources: sources.length > 0 ? sources : undefined
      }]);
    } catch (error) {
      console.error("Chat error", error);
      setMessages(prev => [...prev, { role: 'model', text: "連線錯誤，請稍後再試。", isError: true }]);
    } finally {
      setIsLoading(false);
    }
  };

  // Simple Markdown Renderer
  const renderContent = (text: string) => {
    return text.split('\n').map((line, i) => {
      // Bold
      const parts = line.split(/(\*\*.*?\*\*)/g);
      const renderedLine = parts.map((part, j) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={j} className="text-emerald-400">{part.slice(2, -2)}</strong>;
        }
        return part;
      });

      return <p key={i} className="mb-2 leading-relaxed min-h-[1.2em] whitespace-pre-wrap">{renderedLine.length > 0 ? renderedLine : <br/>}</p>;
    });
  };

  return (
    <div className="w-full max-w-4xl mx-auto h-[600px] flex flex-col bg-slate-800 border border-slate-700 rounded-xl shadow-2xl overflow-hidden animate-in fade-in duration-500">
      {/* Chat Header */}
      <div className="bg-slate-900/50 p-4 border-b border-slate-700 flex items-center justify-between">
        <div className="flex items-center space-x-2">
          <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
          <span className="font-bold text-slate-100">BIAS HUNTER</span>
          <span className="text-xs text-slate-500 px-2 py-0.5 bg-slate-800 rounded border border-slate-700 uppercase">{userType} 模式</span>
        </div>
        <div className="text-xs text-slate-500">即時市場數據已啟用</div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-slate-900/30">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl p-4 ${
              msg.role === 'user' 
                ? 'bg-emerald-900/30 border border-emerald-500/20 text-emerald-100 rounded-tr-none' 
                : 'bg-slate-800 border border-slate-700 text-slate-200 rounded-tl-none'
            } ${msg.isError ? 'border-rose-500/50 text-rose-200' : ''}`}>
              <div className="text-sm">
                {renderContent(msg.text)}
              </div>

              {/* Grounding Sources */}
              {msg.groundingSources && msg.groundingSources.length > 0 && (
                <div className="mt-3 pt-3 border-t border-slate-700/50">
                  <div className="text-xs text-slate-500 mb-1">資料來源：</div>
                  <div className="flex flex-wrap gap-2">
                    {msg.groundingSources.slice(0, 3).map((source, sIdx) => (
                      <a 
                        key={sIdx} 
                        href={source.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="text-xs bg-slate-900/50 hover:bg-slate-900 text-blue-400 px-2 py-1 rounded transition-colors truncate max-w-[200px]"
                      >
