import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { ExperimentPhase, UserChoice, Question, ClassificationResult } from './types';
import { INITIAL_ENDOWMENT, APP_TITLE, APP_MODULE, TOTAL_QUESTIONS } from './constants';
import { generateQuestion, classifyUser, calculateCumulativeScore } from './services/doseService';
import { IntroScreen } from './components/IntroScreen';
import { OptionCard } from './components/OptionCard';
import { ResultsScreen } from './components/ResultsScreen';
import { ChatScreen } from './components/ChatScreen';

const App: React.FC = () => {
  const [phase, setPhase] = useState<ExperimentPhase>(ExperimentPhase.INTRO);
  const [currentQNum, setCurrentQNum] = useState(1);
  const [history, setHistory] = useState<UserChoice[]>([]);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [finalScore, setFinalScore] = useState<number>(INITIAL_ENDOWMENT);

  // Initialize first question when entering experiment phase
  useEffect(() => {
    if (phase === ExperimentPhase.EXPERIMENT && !currentQuestion) {
      const q = generateQuestion(1, []);
      setCurrentQuestion(q);
    }
  }, [phase]);

  const handleChoice = (option: 'A' | 'B') => {
    if (!currentQuestion) return;

    const chosenObj = option === 'A' ? currentQuestion.optionA : currentQuestion.optionB;

    // Record choice
    const choice: UserChoice = {
      questionId: currentQNum,
      chosenOption: option,
      wasLottery: chosenObj.type === 'LOTTERY',
      lotteryParams: chosenObj.params,
      sureAmount: chosenObj.amount || 0
    };

    const newHistory = [...history, choice];
    setHistory(newHistory);

    // Check if finished
    if (currentQNum >= TOTAL_QUESTIONS) {
      const classification = classifyUser(newHistory);
      const score = calculateCumulativeScore(newHistory, INITIAL_ENDOWMENT);

      setResult(classification);
      setFinalScore(score);
      setPhase(ExperimentPhase.RESULTS);
    } else {
      // Generate next question based on history
      const nextQNum = currentQNum + 1;
      const nextQ = generateQuestion(nextQNum, newHistory);
      setCurrentQNum(nextQNum);
      setCurrentQuestion(nextQ);
    }
  };

  // Calculate progress percentage
  const progressPercent = ((currentQNum - 1) / TOTAL_QUESTIONS) * 100;

  return (
    <div className="min-h-screen bg-slate-900 text-slate-100 font-sans selection:bg-emerald-500/30">

      {/* Header */}
      <header className="border-b border-slate-800 bg-slate-900/50 backdrop-blur-sm sticky top-0 z-10">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
            <h1 className="font-bold text-slate-100 tracking-tight">{APP_TITLE}</h1>
          </div>
          <div className="text-xs font-mono text-slate-500 hidden sm:block">
            {APP_MODULE}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-5xl mx-auto px-4 py-8 flex flex-col items-center justify-center min-h-[calc(100vh-4rem)]">

        {phase === ExperimentPhase.INTRO && (
          <IntroScreen onStart={() => setPhase(ExperimentPhase.EXPERIMENT)} />
        )}

        {phase === ExperimentPhase.EXPERIMENT && currentQuestion && (
          <div className="w-full max-w-4xl animate-in fade-in slide-in-from-bottom-4 duration-500">

            {/* Top Bar Status */}
            <div className="mb-8 grid grid-cols-1 md:grid-cols-2 gap-4 items-end">
              {/* Endowment */}
              <div>
                <span className="text-xs text-slate-500 uppercase tracking-wider mb-1 block">當前點數</span>
                <span className="text-4xl font-mono text-white font-bold tracking-tight">
                  {INITIAL_ENDOWMENT.toLocaleString()} <span className="text-lg text-slate-500 font-normal">pts</span>
                </span>
              </div>

              {/* Graphical Progress Bar */}
              <div className="flex flex-col justify-end pb-2">
                <div className="flex justify-between text-xs text-slate-500 mb-2 uppercase tracking-wider">
                  <span>進度</span>
                  <span>{currentQNum} / {TOTAL_QUESTIONS}</span>
                </div>
                <div className="w-full bg-slate-800 h-3 rounded-full overflow-hidden shadow-inner border border-slate-700/50">
                  <div 
                    className="bg-gradient-to-r from-emerald-600 to-emerald-400 h-full transition-all duration-700 ease-out shadow-[0_0_10px_rgba(52,211,153,0.5)]"
                    style={{ width: `${Math.max(5, progressPercent)}%` }}
                  />
                </div>
              </div>
            </div>

            {/* Question Text */}
            <div className="text-center mb-10">
               <h2 className="text-2xl md:text-3xl text-slate-200 font-medium leading-relaxed">
                您更偏好以下哪個選項？
               </h2>
               <p className="text-slate-500 mt-2 text-sm">請依照直覺選擇</p>
            </div>

            {/* Cards Area - Grid Layout */}
            <div className="grid md:grid-cols-2 gap-8">
                <OptionCard 
                  label="選項 A"
                  type={currentQuestion.optionA.type}
                  params={currentQuestion.optionA.params}
                  amount={currentQuestion.optionA.amount}
                  onClick={() => handleChoice('A')}
                />
                <OptionCard 
                  label="選項 B"
                  type={currentQuestion.optionB.type}
                  params={currentQuestion.optionB.params}
                  amount={currentQuestion.optionB.amount}
                  onClick={() => handleChoice('B')}
                />
            </div>
          </div>
        )}

        {phase === ExperimentPhase.RESULTS && result && (
          <ResultsScreen 
            result={result} 
            finalScore={finalScore}
            onContinue={() => setPhase(ExperimentPhase.CHAT)} 
          />
        )}

        {phase === ExperimentPhase.CHAT && result && (
          <ChatScreen userType={result.user_type} />
        )}

      </main>
    </div>
  );
};

export default App;

