    option: "w-full text-center py-4 bg-slate-800 hover:bg-slate-700 text-white font-bold tracking-wide shadow-md hover:shadow-lg uppercase text-sm"
  };

  return (
    <button 
      className={`${baseStyles} ${variants[variant]} ${className}`} 
      {...props}
    >
      {children}
    </button>
  );
};

