             onClick={onRestart} 
             className="px-6"
           >
              重新開始
           </Button>
           <Button onClick={onContinue} className="px-8 shadow-indigo-200">
              下一步
           </Button>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createRoot } from 'react-dom/client';
import { ExperimentPhase, UserChoice, Question, ClassificationResult } from './types';
import { INITIAL_ENDOWMENT, APP_TITLE, APP_MODULE, TOTAL_QUESTIONS } from './constants';
import { generateQuestion, classifyUser, calculateCumulativeScore } from './services/doseService';
import { IntroScreen } from './components/IntroScreen';
import { OptionCard } from './components/OptionCard';
import { ResultsScreen } from './components/ResultsScreen';
import { ChatScreen } from './components/ChatScreen';

const App: React.FC = () => {
  const [phase, setPhase] = useState<ExperimentPhase>(ExperimentPhase.INTRO);
  const [currentQNum, setCurrentQNum] = useState(1);
  const [history, setHistory] = useState<UserChoice[]>([]);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [finalScore, setFinalScore] = useState<number>(INITIAL_ENDOWMENT);

  // Initialize first question when entering experiment phase
  useEffect(() => {
    if (phase === ExperimentPhase.EXPERIMENT && !currentQuestion) {
      const q = generateQuestion(1, []);
      setCurrentQuestion(q);
    }
  }, [phase]);

  const handleChoice = (option: 'A' | 'B') => {
    if (!currentQuestion) return;

    const chosenObj = option === 'A' ? currentQuestion.optionA : currentQuestion.optionB;

    // Record choice
    const choice: UserChoice = {
      questionId: currentQNum,
      chosenOption: option,
      wasLottery: chosenObj.type === 'LOTTERY',
      lotteryParams: chosenObj.params,
      sureAmount: chosenObj.amount || 0
    };

    const newHistory = [...history, choice];
    setHistory(newHistory);

    // Check if finished
    if (currentQNum >= TOTAL_QUESTIONS) {
      const classification = classifyUser(newHistory);
      const score = calculateCumulativeScore(newHistory, INITIAL_ENDOWMENT);

      setResult(classification);
      setFinalScore(score);
      setPhase(ExperimentPhase.RESULTS);
    } else {
      // Generate next question based on history
      const nextQNum = currentQNum + 1;
      const nextQ = generateQuestion(nextQNum, newHistory);
      setCurrentQNum(nextQNum);
      setCurrentQuestion(nextQ);
    }
  };

  const handleRestart = () => {
    setPhase(ExperimentPhase.INTRO);
    setCurrentQNum(1);
    setHistory([]);
    setCurrentQuestion(null);
    setResult(null);
    setFinalScore(INITIAL_ENDOWMENT);
  };

  // Calculate progress percentage
  const progressPercent = ((currentQNum - 1) / TOTAL_QUESTIONS) * 100;

  return (
    <div className="min-h-screen text-slate-800 font-sans selection:bg-indigo-200">

      {/* Header - Glassmorphism */}
      <header className="border-b border-white/50 bg-white/60 backdrop-blur-md sticky top-0 z-10 shadow-sm">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-2 h-2 rounded-full bg-indigo-600 animate-pulse"></div>
            <h1 className="font-bold text-slate-800 tracking-tight">{APP_TITLE}</h1>
          </div>
          <div className="text-xs font-mono text-slate-500 hidden sm:block bg-slate-100/80 px-2 py-1 rounded">
            {APP_MODULE}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-5xl mx-auto px-4 py-8 flex flex-col items-center justify-center min-h-[calc(100vh-4rem)]">

        {phase === ExperimentPhase.INTRO && (
          <IntroScreen onStart={() => setPhase(ExperimentPhase.EXPERIMENT)} />
        )}

        {phase === ExperimentPhase.EXPERIMENT && currentQuestion && (
          <div className="w-full max-w-5xl">

            {/* Top Bar Status - REDESIGNED: Smaller & Less Intrusive */}
            <div className="mb-8 flex flex-col md:flex-row justify-between items-end gap-6 animate-in fade-in duration-700">
              {/* Endowment - Compact */}
              <div className="bg-white/40 backdrop-blur-sm px-5 py-3 rounded-xl border border-white/60 shadow-sm min-w-[220px]">
                <div className="flex items-baseline gap-3 mb-1">
                   <span className="text-xs text-slate-500 font-bold tracking-wider uppercase">起始點數</span>
                   <span className="text-2xl font-mono text-slate-700 font-bold tracking-tight">
                     {INITIAL_ENDOWMENT.toLocaleString()}
                   </span>
                   <span className="text-xs text-slate-400 font-normal">pts</span>
                </div>
                <div className="text-[10px] text-slate-400 font-medium leading-tight">
                  最終點數會在所有決策題目結束後一併計算
                </div>
              </div>

              {/* Graphical Progress Bar */}
              <div className="flex flex-col justify-end w-full md:w-1/3 pb-1">
                <div className="flex justify-between text-xs text-slate-500 mb-2 uppercase tracking-wider font-semibold">
                  <span>決策進度</span>
                  <span>{currentQNum} / {TOTAL_QUESTIONS}</span>
                </div>
                <div className="w-full bg-slate-200 h-2 rounded-full overflow-hidden shadow-inner">
                  <div 
                    className="bg-gradient-to-r from-indigo-500 to-violet-500 h-full transition-all duration-700 ease-out shadow-sm"
                    style={{ width: `${Math.max(5, progressPercent)}%` }}
                  />
                </div>
              </div>
            </div>

            {/* Question Area - WRAPPED IN KEYED DIV FOR ANIMATION */}
            {/* The 'key' prop forces React to remount this div when currentQNum changes, triggering the animation */}
            <div key={currentQNum} className="animate-fade-slide-up">

              {/* Question Text */}
              <div className="text-center mb-10">
                 <h2 className="text-3xl md:text-4xl text-slate-800 font-bold leading-relaxed tracking-tight">
                  您更偏好以下哪個選項？
                 </h2>
                 <p className="text-slate-500 mt-3 text-base">請依照您的直覺進行選擇，無須過度分析。</p>
              </div>

              {/* Cards Area - Grid Layout */}
              <div className="grid md:grid-cols-2 gap-8 lg:gap-12">
                  <OptionCard 
                    label="選項 A"
                    type={currentQuestion.optionA.type}
                    params={currentQuestion.optionA.params}
                    amount={currentQuestion.optionA.amount}
                    onClick={() => handleChoice('A')}
                  />
                  <OptionCard 
                    label="選項 B"
                    type={currentQuestion.optionB.type}
                    params={currentQuestion.optionB.params}
                    amount={currentQuestion.optionB.amount}
                    onClick={() => handleChoice('B')}
                  />
              </div>
            </div>

          </div>
        )}

        {phase === ExperimentPhase.RESULTS && result && (
          <ResultsScreen 
            result={result} 
            finalScore={finalScore}
            onContinue={() => setPhase(ExperimentPhase.CHAT)}
            onRestart={handleRestart}
          />
        )}

        {phase === ExperimentPhase.CHAT && result && (
          <ChatScreen userType={result.user_type} />
        )}

      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { BIAS_HUNTER_SYSTEM_PROMPT } from '../constants';
import { Button } from './Button';

interface ChatScreenProps {
  userType: 'Type A' | 'Type B';
}

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
  groundingSources?: Array<{ uri: string; title: string }>;
}

export const ChatScreen: React.FC<ChatScreenProps> = ({ userType }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [chatSession, setChatSession] = useState<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    // Initialize Gemini Chat
    try {
      if (!process.env.API_KEY) {
        throw new Error("API Key not found");
      }
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const systemInstruction = BIAS_HUNTER_SYSTEM_PROMPT.replace('{{USER_TYPE}}', userType);

      const chat = ai.chats.create({
        model: 'gemini-2.5-flash',
        config: {
          systemInstruction: systemInstruction,
          tools: [{ googleSearch: {} }]
        },
      });

      setChatSession(chat);

      // Initial greeting
      // Map userType to descriptive Chinese name for the greeting
      const userRoleName = userType === 'Type A' ? '「哨兵 (Sentinel)」' : '「特立獨行者 (Maverick)」';

      setMessages([{
        role: 'model',
        text: `我是您的投資審計員 (Bias Hunter)。我看到您被歸類為 **${userRoleName}**。\n\n請告訴我您目前的交易計劃（例如：「我想賣掉 NVDA」或「我想買入 TSM」），我將根據市場數據審核您的決定。`
      }]);

    } catch (error) {
      console.error("Failed to init chat", error);
      setMessages([{ role: 'model', text: '系統初始化失敗：缺少 API 金鑰。請檢查環境設定。', isError: true }]);
    }
  }, [userType]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim() || !chatSession || isLoading) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', text: userMsg }]);
    setIsLoading(true);

    try {
      const result = await chatSession.sendMessage({ message: userMsg });
      let responseText = result.text || "無法生成回應。";

      // Detect and strip JSON block meant for internal logging
      const jsonBlockRegex = /```json\s*(\{[\s\S]*?\})\s*```/;
      const match = responseText.match(jsonBlockRegex);

      if (match) {
        responseText = responseText.replace(match[0], '').trim();
      }

      // Extract grounding metadata (sources)
      const groundingChunks = result.candidates?.[0]?.groundingMetadata?.groundingChunks;
      const sources: Array<{ uri: string; title: string }> = [];

      if (groundingChunks) {
        groundingChunks.forEach(chunk => {
          if (chunk.web?.uri && chunk.web?.title) {
            sources.push({ uri: chunk.web.uri, title: chunk.web.title });
          }
        });
      }

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: responseText,
        groundingSources: sources.length > 0 ? sources : undefined
      }]);
    } catch (error) {
      console.error("Chat error", error);
      setMessages(prev => [...prev, { role: 'model', text: "連線錯誤，請稍後再試。", isError: true }]);
    } finally {
      setIsLoading(false);
    }
  };

  // Simple Markdown Renderer
  const renderContent = (text: string) => {
    // Helper to process bold within a string
    const processBold = (content: string) => {
      const parts = content.split(/(\*\*.*?\*\*)/g);
      return parts.map((part, index) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={`b-${index}`} className="text-indigo-600 font-semibold">{part.slice(2, -2)}</strong>;
        }
        return <span key={`t-${index}`}>{part}</span>;
      });
    };

    return text.split('\n').map((line, i) => {
      // Regex for markdown links: [text](url)
      const linkRegex = /\[([^\]]+)\]\(([^)]+)\)/g;
      const elements: React.ReactNode[] = [];
      let lastIndex = 0;
      let match;

      while ((match = linkRegex.exec(line)) !== null) {
        const [_, linkText, linkUrl] = match;
        const index = match.index;

        // Text before link
        if (index > lastIndex) {
          elements.push(...processBold(line.slice(lastIndex, index)));
        }

        // Link
        elements.push(
          <a
            key={`link-${i}-${index}`}
            href={linkUrl}
            target="_blank"
            rel="noopener noreferrer"
            className="text-indigo-500 hover:text-indigo-700 underline underline-offset-2 transition-colors"
          >
            {linkText}
          </a>
        );

        lastIndex = linkRegex.lastIndex;
      }

      // Remaining text
      if (lastIndex < line.length) {
        elements.push(...processBold(line.slice(lastIndex)));
      }

      if (elements.length === 0 && line.length === 0) {
        return <div key={i} className="h-4" />;
      }

      return (
        <p key={i} className="mb-2 leading-relaxed whitespace-pre-wrap text-slate-700">
          {elements.length > 0 ? elements : <span className="invisible">.</span>}
        </p>
      );
    });
  };

  return (
    <div className="w-full max-w-4xl mx-auto h-[600px] flex flex-col bg-white/70 backdrop-blur-xl border border-white/80 rounded-3xl shadow-[0_8px_30px_rgb(0,0,0,0.04)] overflow-hidden animate-in fade-in duration-500">
      {/* Chat Header */}
      <div className="bg-white/50 p-4 border-b border-slate-100 flex items-center justify-between backdrop-blur-sm">
        <div className="flex items-center space-x-3">
          <div className="w-8 h-8 rounded-full bg-indigo-600 flex items-center justify-center text-white font-bold text-xs">BH</div>
          <div>
            <span className="font-bold text-slate-800 block leading-tight">BIAS HUNTER</span>
            <span className="text-xs text-slate-500">投資審計顧問</span>
          </div>
        </div>
        {/* Removed the mode badge as requested */}
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-6 space-y-6 bg-slate-50/30">
        {messages.map((msg, idx) => (
          <div key={idx} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] rounded-2xl p-5 shadow-sm ${
              msg.role === 'user' 
                ? 'bg-slate-800 text-white rounded-tr-none' 
                : 'bg-white border border-white/80 text-slate-700 rounded-tl-none'
            } ${msg.isError ? 'border-rose-200 bg-rose-50 text-rose-700' : ''}`}>
              <div className={`text-base ${msg.role === 'user' ? 'text-slate-100' : ''}`}>
                {renderContent(msg.text)}
              </div>

              {/* Grounding Sources */}
              {msg.groundingSources && msg.groundingSources.length > 0 && (
                <div className="mt-4 pt-3 border-t border-slate-100">
                  <div className="text-xs text-slate-400 mb-2 uppercase tracking-wider font-semibold">資料來源：</div>
                  <div className="flex flex-wrap gap-2">
                    {msg.groundingSources.slice(0, 3).map((source, sIdx) => (
                      <a 
                        key={sIdx} 
                        href={source.uri} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="text-xs bg-slate-100 hover:bg-slate-200 text-indigo-600 px-3 py-1.5 rounded-lg transition-colors truncate max-w-[200px] border border-slate-200"
                      >
                        {source.title}
                      </a>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
             <div className="bg-white border border-white/80 shadow-sm rounded-2xl rounded-tl-none p-4 flex items-center space-x-2">
               <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '0ms' }}></div>
               <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '150ms' }}></div>
               <div className="w-2 h-2 bg-indigo-400 rounded-full animate-bounce" style={{ animationDelay: '300ms' }}></div>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <form onSubmit={handleSend} className="p-4 bg-white/60 border-t border-slate-100 backdrop-blur-md flex gap-4">
        <input 
          type="text" 
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="輸入您的交易想法..."
          className="flex-1 bg-white border border-slate-200 rounded-xl px-5 py-3 text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all shadow-sm"
          disabled={isLoading}
        />
        <Button type="submit" disabled={!input || isLoading} className="px-6 rounded-xl">
          發送
        </Button>
      </form>
    </div>
  );
};

