import { GoogleGenAI, Type } from "@google/genai";
import { HISTORICAL_SCANNER_SYSTEM_PROMPT } from '../constants';
import { HistoryAnalysisResult } from '../types';

/**
 * Converts a File object to a Base64 string for the API
 */
const fileToPart = async (file: File) => {
  return new Promise<string>((resolve, reject) => {
    const reader = new FileReader();
    reader.onloadend = () => {
      const result = reader.result as string;
      // Remove the Data URL prefix (e.g., "data:image/jpeg;base64,")
      const base64 = result.split(',')[1];
      resolve(base64);
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
};

/**
 * Analyzes the brokerage statement using Gemini
 */
export const analyzeBrokerageStatement = async (file: File): Promise<HistoryAnalysisResult> => {
  if (!process.env.API_KEY) {
    throw new Error("API Key not found");
  }

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const base64Data = await fileToPart(file);

  const model = 'gemini-2.5-flash'; // Flash is sufficient and fast for OCR + Search

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: [
        {
          role: 'user',
          parts: [
            {
              inlineData: {
                mimeType: file.type,
                data: base64Data
              }
            },
            {
              text: "Analyze this brokerage statement image. Extract transactions, look up their historical market context using Google Search, and diagnose the behavioral biases. Return JSON."
            }
          ]
        }
      ],
      config: {
        systemInstruction: HISTORICAL_SCANNER_SYSTEM_PROMPT,
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        // Defining schema helps ensure consistent JSON output
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            module: { type: Type.STRING },
            data_source: { type: Type.STRING },
            transactions: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  date: { type: Type.STRING },
                  symbol: { type: Type.STRING },
                  action: { type: Type.STRING, enum: ["Buy", "Sell"] },
                  price: { type: Type.NUMBER },
                  market_context: { type: Type.STRING },
                  behavior_diagnosis: { type: Type.STRING },
                  bias_tag: { type: Type.STRING }
                },
                required: ["date", "symbol", "action", "market_context", "bias_tag"]
              }
            },
            behavioral_summary: {
              type: Type.OBJECT,
              properties: {
                win_loss_tilt: { type: Type.STRING },
                risk_appetite: { type: Type.STRING }
              }
            },
            dominant_biases: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          }
        }
      }
    });

    const text = response.text || "{}";
    const jsonResult = JSON.parse(text) as HistoryAnalysisResult;
    return jsonResult;

  } catch (error) {
    console.error("Historical Analysis Failed:", error);
    throw error;
  }
};

