// Mini-Game Component for Loading State
const LoadingGame = ({ onScoreUpdate, count }: { onScoreUpdate: (delta: number) => void, count: number }) => {
  const [bubbles, setBubbles] = useState<{id: number, x: number, text: string, speed: number, type: 'bad' | 'good'}[]>([]);

  useEffect(() => {
    const interval = setInterval(() => {
      const id = Date.now();

      // 70% chance to spawn a "Bad" bias bubble (Target), 30% chance for "Good" trait (Trap)
      const isBad = Math.random() > 0.3;

      let text = '';
      if (isBad) {
        const badTexts = ['FOMO', 'Panic', 'Greed', 'Fear', 'Hype', 'Rumor', 'Impulse', 'Noise', 'Bias'];
        text = badTexts[Math.floor(Math.random() * badTexts.length)];
      } else {
        const goodTexts = ['Logic', 'Plan', 'Data', 'Calm', 'Hold', 'Value', 'Patience'];
        text = goodTexts[Math.floor(Math.random() * goodTexts.length)];
      }

      const x = Math.random() * 70 + 15; // Keep away from extreme edges (15% to 85%)
      // Slower speed: 0.3 to 0.7
      const speed = Math.random() * 0.4 + 0.3; 

      setBubbles(prev => [...prev, { id, x, text, speed, type: isBad ? 'bad' : 'good' }]);
    }, 1000); // Slower spawn rate (1000ms instead of 600ms)

    return () => clearInterval(interval);
  }, []);

  const handleBubbleClick = (id: number, type: 'bad' | 'good') => {
    setBubbles(prev => prev.filter(b => b.id !== id));
    // If it's a 'bad' bubble (Bias), +1 point. If 'good' (Virtue), -1 point.
    onScoreUpdate(type === 'bad' ? 1 : -1);
  };

  return (
    <div className="w-full h-[360px] relative overflow-hidden bg-slate-800 rounded-2xl flex flex-col items-center justify-center text-center p-6 shadow-inner border border-slate-700 animate-in fade-in duration-500">
        <style>{`
          @keyframes floatUp {
            0% { transform: translateY(200px); opacity: 0; }
            10% { opacity: 1; }
            100% { transform: translateY(-350px); opacity: 0; }
          }
        `}</style>

        <div className="z-20 flex flex-col items-center pointer-events-none">
            {/* Loading Spinner Area */}
            <div className="w-12 h-12 mb-4 relative">
                <div className="absolute inset-0 border-4 border-indigo-500/30 rounded-full"></div>
                <div className="absolute inset-0 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin"></div>
            </div>

            <h3 className="text-white font-bold text-lg mb-1">正在深入分析市場數據...</h3>
            <p className="text-indigo-200 text-sm mb-6">分析中，這需要一段時間</p>

            {/* Instruction Text - Moved Up & Highlighted */}
            <p className="text-xs font-bold text-amber-300 mb-2 animate-pulse bg-slate-900/50 px-3 py-1 rounded-full border border-amber-500/30">
               消除紅色的偏差氣泡 (+1)，保留綠色的優良特質 (-1)
            </p>

            {/* Score Display */}
            <div className="bg-white/10 backdrop-blur-md border border-white/10 rounded-xl p-3 flex flex-col items-center min-w-[140px]">
                <span className="text-[10px] text-indigo-300 uppercase tracking-widest font-bold mb-1">已消除偏差</span>
                <span className={`text-3xl font-mono font-bold tabular-nums transition-colors duration-300 ${count < 0 ? 'text-rose-400' : 'text-white'}`}>
                  {count}
                </span>
            </div>
        </div>

        {/* Bubble Layer */}
        {bubbles.map(b => (
           <div 
             key={b.id}
             onMouseDown={() => handleBubbleClick(b.id, b.type)} // Use onMouseDown for faster response
             className="absolute bottom-0 cursor-pointer select-none z-10 hover:scale-110 active:scale-95 transition-transform"
             style={{ 
               left: `${b.x}%`, 
               animation: `floatUp ${5 / b.speed}s linear forwards` // Slower animation duration
             }}
             onAnimationEnd={() => setBubbles(prev => prev.filter(item => item.id !== b.id))}
           >
             <div className={`
               backdrop-blur-md shadow-lg border px-5 py-2.5 rounded-full text-sm font-bold tracking-wide
               ${b.type === 'bad' 
                 ? 'bg-rose-500/40 hover:bg-rose-500/80 border-rose-400 text-rose-50' 
                 : 'bg-emerald-500/40 hover:bg-emerald-500/80 border-emerald-400 text-emerald-50'}
             `}>
               {b.text}
             </div>
           </div>
        ))}
    </div>
  );
};

