         <button 
           onClick={handleDailyPushClick}
           className="text-xs font-bold text-slate-500 hover:text-amber-600 bg-white border border-slate-200 hover:border-amber-300 px-3 py-1.5 rounded-full transition-all flex items-center gap-1.5 shadow-sm"
         >
            <span>🔔</span>
            智能推播
         </button>
      </div>

      {/* Input Area */}
      <form onSubmit={(e) => handleSend(e)} className="p-4 bg-white/60 border-t border-slate-100 backdrop-blur-md flex gap-4">
        <input 
          ref={inputRef}
          type="text" 
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="輸入您的交易想法，或貼上新聞連結..."
          className="flex-1 bg-white border border-slate-200 rounded-xl px-5 py-3 text-slate-800 placeholder-slate-400 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all shadow-sm"
          disabled={isLoading}
        />
        <Button type="submit" disabled={!input || isLoading} className="px-6 rounded-xl">
          發送
        </Button>
      </form>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { ExperimentPhase, UserChoice, Question, ClassificationResult, AnalyzedTransaction } from './types';
import { INITIAL_ENDOWMENT, APP_TITLE, APP_MODULE, TOTAL_QUESTIONS } from './constants';
import { generateQuestion, classifyUser, calculateCumulativeScore } from './services/doseService';
import { IntroScreen } from './components/IntroScreen';
import { OptionCard } from './components/OptionCard';
import { ResultsScreen } from './components/ResultsScreen';
import { ChatScreen } from './components/ChatScreen';
import { HistoryUploadScreen } from './components/HistoryUploadScreen';

const STORAGE_KEY = 'bias_hunter_v1_data';

const App: React.FC = () => {
  // --- States ---
  const [phase, setPhase] = useState<ExperimentPhase>(ExperimentPhase.INTRO);
  const [currentQNum, setCurrentQNum] = useState(1);
  const [history, setHistory] = useState<UserChoice[]>([]);
  const [currentQuestion, setCurrentQuestion] = useState<Question | null>(null);
  const [result, setResult] = useState<ClassificationResult | null>(null);
  const [finalScore, setFinalScore] = useState<number>(INITIAL_ENDOWMENT);
  const [transactions, setTransactions] = useState<AnalyzedTransaction[]>([]);
  const [isHistoryModalOpen, setIsHistoryModalOpen] = useState(false);
  const [isInitialized, setIsInitialized] = useState(false);

  // --- Persistence Logic: Load ---
  useEffect(() => {
    const savedData = localStorage.getItem(STORAGE_KEY);
    if (savedData) {
      try {
        const parsed = JSON.parse(savedData);
        setPhase(parsed.phase || ExperimentPhase.INTRO);
        setCurrentQNum(parsed.currentQNum || 1);
        setHistory(parsed.history || []);
        setResult(parsed.result || null);
        setFinalScore(parsed.finalScore || INITIAL_ENDOWMENT);
        setTransactions(parsed.transactions || []);
      } catch (e) {
        console.error("Failed to load persistence data", e);
      }
    }
    setIsInitialized(true);
  }, []);

  // --- Persistence Logic: Save ---
  useEffect(() => {
    if (!isInitialized) return;

    const dataToSave = {
      phase,
      currentQNum,
      history,
      result,
      finalScore,
      transactions
    };
    localStorage.setItem(STORAGE_KEY, JSON.stringify(dataToSave));
  }, [phase, currentQNum, history, result, finalScore, transactions, isInitialized]);

  // --- Question Management ---
  useEffect(() => {
    if (phase === ExperimentPhase.EXPERIMENT && isInitialized) {
      // Generate question based on current state (either 1st or the one user left off at)
      const q = generateQuestion(currentQNum, history);
      setCurrentQuestion(q);
    }
  }, [phase, currentQNum, isInitialized]);

  const handleChoice = (option: 'A' | 'B') => {
    if (!currentQuestion) return;

    const chosenObj = option === 'A' ? currentQuestion.optionA : currentQuestion.optionB;

    const choice: UserChoice = {
      questionId: currentQNum,
      chosenOption: option,
      wasLottery: chosenObj.type === 'LOTTERY',
      lotteryParams: chosenObj.params,
      sureAmount: chosenObj.amount || 0
    };

    const newHistory = [...history, choice];
    setHistory(newHistory);

    if (currentQNum >= TOTAL_QUESTIONS) {
      const classification = classifyUser(newHistory);
      const score = calculateCumulativeScore(newHistory, INITIAL_ENDOWMENT);

      setResult(classification);
      setFinalScore(score);
      setPhase(ExperimentPhase.RESULTS);
    } else {
      const nextQNum = currentQNum + 1;
      setCurrentQNum(nextQNum);
      // currentQuestion will be updated by the useEffect above
    }
  };

  const handleRestart = () => {
    if (window.confirm("確定要重設所有資料嗎？這將會清空您的測驗結果與交易資料庫。")) {
      localStorage.removeItem(STORAGE_KEY);
      setPhase(ExperimentPhase.INTRO);
      setCurrentQNum(1);
      setHistory([]);
      setCurrentQuestion(null);
      setResult(null);
      setFinalScore(INITIAL_ENDOWMENT);
      setTransactions([]);
    }
  };

  const handleAddTransactions = (newTxs: AnalyzedTransaction[]) => {
    setTransactions(prev => [...prev, ...newTxs]);
  };

  if (!isInitialized) {
    return (
      <div className="min-h-screen bg-slate-50 flex items-center justify-center">
        <div className="w-8 h-8 border-4 border-indigo-600 border-t-transparent rounded-full animate-spin"></div>
      </div>
    );
  }

  const progressPercent = ((currentQNum - 1) / TOTAL_QUESTIONS) * 100;

  return (
    <div className="min-h-screen text-slate-800 font-sans selection:bg-indigo-200">

      {/* Header */}
      <header className="border-b border-white/50 bg-white/60 backdrop-blur-md sticky top-0 z-10 shadow-sm">
        <div className="max-w-5xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="flex items-center space-x-3">
            <div className="w-2 h-2 rounded-full bg-indigo-600 animate-pulse"></div>
            <h1 className="font-bold text-slate-800 tracking-tight">{APP_TITLE}</h1>
          </div>
          <div className="text-xs font-mono text-slate-500 hidden sm:block bg-slate-100/80 px-2 py-1 rounded">
            {APP_MODULE}
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-5xl mx-auto px-4 py-8 flex flex-col items-center justify-center min-h-[calc(100vh-4rem)] relative">

        {phase === ExperimentPhase.INTRO && (
          <IntroScreen onStart={() => setPhase(ExperimentPhase.EXPERIMENT)} />
        )}

        {phase === ExperimentPhase.EXPERIMENT && currentQuestion && (
          <div className="w-full max-w-5xl">
            <div className="mb-8 flex flex-col md:flex-row justify-between items-end gap-6 animate-in fade-in duration-700">
              <div className="bg-white/40 backdrop-blur-sm px-5 py-3 rounded-xl border border-white/60 shadow-sm min-w-[220px]">
                <div className="flex items-baseline gap-3 mb-1">
                   <span className="text-xs text-slate-500 font-bold tracking-wider uppercase">起始點數</span>
                   <span className="text-2xl font-mono text-slate-700 font-bold tracking-tight">
                     {INITIAL_ENDOWMENT.toLocaleString()}
                   </span>
                   <span className="text-xs text-slate-400 font-normal">pts</span>
                </div>
                <div className="text-[10px] text-slate-400 font-medium leading-tight">
                  最終點數會在所有決策題目結束後一併計算
                </div>
              </div>

              <div className="flex flex-col justify-end w-full md:w-1/3 pb-1">
                <div className="flex justify-between text-xs text-slate-500 mb-2 uppercase tracking-wider font-semibold">
                  <span>決策進度</span>
                  <span>{currentQNum} / {TOTAL_QUESTIONS}</span>
                </div>
                <div className="w-full bg-slate-200 h-2 rounded-full overflow-hidden shadow-inner">
                  <div 
                    className="bg-gradient-to-r from-indigo-500 to-violet-500 h-full transition-all duration-700 ease-out shadow-sm"
                    style={{ width: `${Math.max(5, progressPercent)}%` }}
                  />
                </div>
              </div>
            </div>

            <div key={currentQNum} className="animate-fade-slide-up">
              <div className="text-center mb-10">
                 <h2 className="text-3xl md:text-4xl text-slate-800 font-bold leading-relaxed tracking-tight">
                  您更偏好以下哪個選項？
                 </h2>
                 <p className="text-slate-500 mt-3 text-base">請依照您的直覺進行選擇，無須過度分析。</p>
              </div>

              <div className="grid md:grid-cols-2 gap-8 lg:gap-12">
                  <OptionCard 
                    label="選項 A"
                    type={currentQuestion.optionA.type}
                    params={currentQuestion.optionA.params}
                    amount={currentQuestion.optionA.amount}
                    onClick={() => handleChoice('A')}
                  />
                  <OptionCard 
                    label="選項 B"
                    type={currentQuestion.optionB.type}
                    params={currentQuestion.optionB.params}
                    amount={currentQuestion.optionB.amount}
                    onClick={() => handleChoice('B')}
                  />
              </div>
            </div>
          </div>
        )}

        {phase === ExperimentPhase.RESULTS && result && (
          <ResultsScreen 
            result={result} 
            finalScore={finalScore}
            onContinue={() => setPhase(ExperimentPhase.HISTORY_SCAN)}
            onRestart={handleRestart}
          />
        )}

        {phase === ExperimentPhase.HISTORY_SCAN && (
          <HistoryUploadScreen 
            existingTransactions={transactions}
            onAddTransactions={handleAddTransactions}
            onNext={() => setPhase(ExperimentPhase.CHAT)}
          />
        )}

        {phase === ExperimentPhase.CHAT && result && (
          <ChatScreen 
            userType={result.user_type}
            transactions={transactions}
            onOpenHistory={() => setIsHistoryModalOpen(true)}
          />
        )}

      </main>

      {/* MODAL OVERLAY FOR HISTORY DB */}
      {isHistoryModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 md:p-8 bg-slate-900/40 backdrop-blur-sm animate-in fade-in duration-200">
           <div className="bg-white w-full max-w-5xl h-[85vh] rounded-3xl shadow-2xl overflow-hidden relative animate-in zoom-in-95 duration-200">
              <HistoryUploadScreen 
                existingTransactions={transactions}
                onAddTransactions={handleAddTransactions}
                onClose={() => setIsHistoryModalOpen(false)}
                isModal={true}
              />
           </div>
        </div>
      )}

      {/* Global Persistence Reset - Optional but helpful if stuck */}
      {phase === ExperimentPhase.CHAT && (
        <button 
          onClick={handleRestart}
          className="fixed bottom-4 left-4 text-[10px] text-slate-300 hover:text-slate-500 transition-colors uppercase tracking-widest font-bold"
        >
          Reset Session
        </button>
      )}

    </div>
  );
};

export default App;

export enum ExperimentPhase {
  INTRO = 'INTRO',
  EXPERIMENT = 'EXPERIMENT',
  RESULTS = 'RESULTS',
  HISTORY_SCAN = 'HISTORY_SCAN',
  CHAT = 'CHAT'
}

export enum OptionType {
  LOTTERY = 'LOTTERY',
  SURE_THING = 'SURE_THING'
}

export interface LotteryParams {
  gain: number;
  loss: number;
  probability: number; // 0.0 to 1.0 (e.g. 0.05 for 5%)
}

export interface Question {
  id: number;
  text: string;
  optionA: {
    type: OptionType;
    params?: LotteryParams; // If Lottery
    amount?: number; // If Sure Thing
  };
  optionB: {
    type: OptionType;
    // Added params here to fix TS errors in App.tsx (Line 78 and 198) 
    // where optionB is accessed in a context that expects potential lottery parameters.
    params?: LotteryParams; 
    amount: number; // Usually 0 or a sure gain/loss
  };
}

export interface UserChoice {
  questionId: number;
  chosenOption: 'A' | 'B';
  wasLottery: boolean;
  lotteryParams?: LotteryParams;
  sureAmount: number;
}

// Updated User Types
export type UserProfileType = 'The Sentinel' | 'The Adventurer';

export interface ClassificationResult {
  module: string;
  total_questions: number;
  user_type: UserProfileType;
  traits: {
    loss_aversion: 'High' | 'Low';
    probability_weighting: 'Overweights Small Prob' | 'Underweights High Prob' | 'Rational';
  };
  summary: string;
}

export interface AnalyzedTransaction {
  date: string;
  symbol: string;
  action: 'Buy' | 'Sell';
  price: number;
  market_context: string;
  behavior_diagnosis: string;
  bias_tag: string;
}

export interface HistoryAnalysisResult {
  module: string;
  data_source: string;
  transactions: AnalyzedTransaction[];
  behavioral_summary: {
    win_loss_tilt: string;
    risk_appetite: string;
  };
  dominant_biases: string[];
}

import React, { useState, useEffect, useRef, useMemo } from 'react';
import { GoogleGenAI, Chat, GenerateContentResponse } from "@google/genai";
import { BIAS_HUNTER_SYSTEM_PROMPT } from '../constants';
import { Button } from './Button';
import { AnalyzedTransaction, UserProfileType } from '../types';

interface ChatScreenProps {
  userType: UserProfileType;
  transactions: AnalyzedTransaction[];
  onOpenHistory: () => void;
}

interface QuizData {
  module: string;
  question: string;
  options: { label: string; text: string }[];
}

interface Message {
  role: 'user' | 'model';
  text: string;
  isError?: boolean;
  groundingSources?: Array<{ uri: string; title: string }>;
  quizData?: QuizData;
}

type EmotionalState = 'Balanced (平衡)' | 'Overheated (過熱)' | 'Anxious (焦慮)';

export const ChatScreen: React.FC<ChatScreenProps> = ({ userType, transactions, onOpenHistory }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [chatSession, setChatSession] = useState<Chat | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const inputRef = useRef<HTMLInputElement>(null);

  // Calculate "Current State" based on recent transaction tags
  const currentState: EmotionalState = useMemo(() => {
    if (transactions.length === 0) return 'Balanced (平衡)';

    // Analyze last 5 transactions for recent state
    const recent = transactions.slice(-5);

    let heatScore = 0; // + for FOMO/Greed, - for Panic/Fear

    recent.forEach(t => {
      const tag = t.bias_tag || '';
      if (tag.includes('追高') || tag.includes('衝動') || tag.includes('過度交易') || tag.includes('貪婪')) {
        heatScore += 1;
      } else if (tag.includes('殺低') || tag.includes('恐慌') || tag.includes('恐懼') || tag.includes('不敢')) {
        heatScore -= 1;
      }
    });

    if (heatScore >= 2) return 'Overheated (過熱)';
    if (heatScore <= -2) return 'Anxious (焦慮)';
    return 'Balanced (平衡)';
  }, [transactions]);

  // Initialize Chat Session
  useEffect(() => {
    try {
      if (!process.env.API_KEY) {
        throw new Error("API Key not found");
      }
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Format history for context
      const historyStr = transactions.length > 0 
        ? JSON.stringify(transactions.map(t => ({
            date: t.date,
            symbol: t.symbol,
            action: t.action,
            bias: t.bias_tag
          }))) 
        : "No history available.";

      let systemInstruction = BIAS_HUNTER_SYSTEM_PROMPT.replace(/{{USER_TYPE}}/g, userType);
      systemInstruction = systemInstruction.replace(/{{CURRENT_STATE}}/g, currentState);
      systemInstruction = systemInstruction.replace('{{HISTORY_DATA}}', historyStr);

      // Using 'gemini-3-flash-preview' for robust text tasks and search grounding.
      const chat = ai.chats.create({
        model: 'gemini-3-flash-preview',
        config: {
          systemInstruction: systemInstruction,
          tools: [{ googleSearch: {} }]
        },
      });

      setChatSession(chat);

      // Initial greeting logic - only if no messages exist
      if (messages.length === 0) {
        const userRoleName = userType === 'The Sentinel' ? '「哨兵 (The Sentinel)」' : '「冒險家 (The Adventurer)」';

        let greeting = `### 🟢 投資審計程序已啟動\n我是您的專屬投資審計員 (Bias Hunter)。\n\n**核心人格：** ${userRoleName}\n**當前狀態：** ${currentState}`;

        if (transactions.length > 0) {
           greeting += `\n\n已載入 **${transactions.length} 筆**歷史交易紀錄。系統偵測到您的心理狀態目前為 **${currentState}**，我將據此動態調整風險控管的強度與建議語氣。`;
        } else {
           greeting += `\n\n目前尚未載入歷史數據，我將以標準模式為您服務。`;
        }

        greeting += `\n\n**您可以試著告訴我您的交易計劃，例如：**\n` +
                    `*   「我想在 130 買進 NVDA，因為財報預期很好...」\n` +
                    `*   「TSLA 跌破支撐了，我該現在認賠賣出嗎？」\n` +
                    `*   「現在市場是否過熱？請幫我檢查。」\n\n` +
                    `或者，點擊下方 **「新聞過濾」** 按鈕，讓我幫您過濾市場雜訊，避免決策受情緒干擾。`;

        setMessages([{
          role: 'model',
          text: greeting
        }]);
      }

    } catch (error) {
      console.error("Failed to init chat", error);
      if (messages.length === 0) {
         setMessages([{ role: 'model', text: '系統初始化失敗：缺少 API 金鑰。', isError: true }]);
      }
    }
  }, [userType, transactions, currentState]); 

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSend = async (e: React.FormEvent, overrideMsg?: string) => {
    if (e) e.preventDefault();
    const msgToSend = overrideMsg || input.trim();

    if (!msgToSend || !chatSession || isLoading) return;

    if (!overrideMsg) setInput('');

    setMessages(prev => [...prev, { role: 'user', text: msgToSend }]);
    setIsLoading(true);

    try {
      const result = await chatSession.sendMessage({ message: msgToSend });
      let responseText = result.text || "無法生成回應。";
      let quizData: QuizData | undefined;

      const jsonBlockRegex = /```json\s*(\{[\s\S]*?\})\s*```/;
      const match = responseText.match(jsonBlockRegex);

      if (match) {
        try {
          const parsed = JSON.parse(match[1]);
          if (parsed.module === "News_Quiz") {
             quizData = parsed as QuizData;
             responseText = responseText.replace(match[0], '').trim();
          } else {
             responseText = responseText.replace(match[0], '').trim();
          }
        } catch (e) {
          console.warn("Failed to parse JSON response", e);
        }
      }

      const groundingChunks = result.candidates?.[0]?.groundingMetadata?.groundingChunks;
      const sources: Array<{ uri: string; title: string }> = [];
      if (groundingChunks) {
        groundingChunks.forEach(chunk => {
          if (chunk.web?.uri && chunk.web?.title) {
            sources.push({ uri: chunk.web.uri, title: chunk.web.title });
          }
        });
      }

      setMessages(prev => [...prev, { 
        role: 'model', 
        text: responseText,
        groundingSources: sources.length > 0 ? sources : undefined,
        quizData: quizData
      }]);
    } catch (error) {
      console.error("Chat error", error);
      setMessages(prev => [...prev, { role: 'model', text: "連線錯誤，請稍後再試。", isError: true }]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleNewsFilterClick = () => {
    setInput('[新聞過濾] 請幫我分析這則新聞：');
    if (inputRef.current) {
      inputRef.current.focus();
    }
  };

  const handleDailyPushClick = () => {
    handleSend({ preventDefault: () => {} } as React.FormEvent, '[智能推播] 請提供今日適合我的 3 則新聞');
  };

  const handleQuizOptionClick = (label: string, text: string) => {
     handleSend({ preventDefault: () => {} } as React.FormEvent, `我選擇答案 ${label}：${text}`);
  };

  const renderContent = (text: string) => {
    const processBold = (content: string) => {
      const parts = content.split(/(\*\*.*?\*\*)/g);
      return parts.map((part, index) => {
        if (part.startsWith('**') && part.endsWith('**')) {
          return <strong key={`b-${index}`} className="text-indigo-600 font-semibold">{part.slice(2, -2)}</strong>;
        }
        return <span key={`t-${index}`}>{part}</span>;
      });
    };

    return text.split('\n').map((line, i) => {
      const linkRegex = /\[([^\]]+)\]\(([^)]+)\)/g;
      const elements: React.ReactNode[] = [];
      let lastIndex = 0;
      let match;
      while ((match = linkRegex.exec(line)) !== null) {
        const [_, linkText, linkUrl] = match;
        const index = match.index;
        if (index > lastIndex) elements.push(...processBold(line.slice(lastIndex, index)));
        elements.push(
          <a key={`link-${i}-${index}`} href={linkUrl} target="_blank" rel="noopener noreferrer" className="text-indigo-500 hover:text-indigo-700 underline underline-offset-2 transition-colors">
            {linkText}
          </a>
        );
        lastIndex = linkRegex.lastIndex;
      }
      if (lastIndex < line.length) elements.push(...processBold(line.slice(lastIndex)));
      if (elements.length === 0 && line.length === 0) return <div key={i} className="h-4" />;

      return <p key={i} className="mb-2 leading-relaxed whitespace-pre-wrap break-words">{elements.length > 0 ? elements : <span className="invisible">.</span>}</p>;
    });
  };

  const getStateColor = (state: EmotionalState) => {
    if (state.includes('過熱')) return 'bg-rose-100 text-rose-600 border-rose-200';
    if (state.includes('焦慮')) return 'bg-amber-100 text-amber-600 border-amber-200';
    return 'bg-emerald-100 text-emerald-600 border-emerald-200';
  };

